void os::Linux::install_signal_handlers() {
  if (!signal_handlers_are_installed) {
    signal_handlers_are_installed = true;
    //省略无关代码..
    //以下是注册上面表格中列出的信号
    set_signal_handler(SIGSEGV, true);
